        .into_json()
        .map_err(|e| RuntimeError::InvalidArgument {
            func: "llm_call".into(),
            reason: format!("invalid JSON from {resolved}: {e}"),
        })?;
    parse_response(&json)
}

/// Normalize the user-supplied URL: strip trailing
/// slashes, then append `/api/generate` unless the
/// URL already ends with it.
fn resolve_url(base: &str) -> String {
    let trimmed = base.trim_end_matches('/');
    if trimmed.ends_with("/api/generate") {
        trimmed.into()
    } else {
        format!("{trimmed}/api/generate")
    }
}

/// Pull the top-level `response` string field out of
/// an Ollama `/api/generate` reply.
fn parse_response(json: &serde_json::Value) -> Result<String, RuntimeError> {
    json.get("response")
        .and_then(|v| v.as_str())
        .map(str::to_string)
        .ok_or_else(|| RuntimeError::InvalidArgument {
            func: "llm_call".into(),
            reason: format!("response JSON missing string `response` field: {json}"),
        })
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn resolve_url_appends_api_generate() {
        assert_eq!(
            resolve_url("http://localhost:11434"),
            "http://localhost:11434/api/generate"
        );
    }

    #[test]
    fn resolve_url_strips_trailing_slash_then_appends() {
        assert_eq!(
            resolve_url("http://localhost:11434/"),
            "http://localhost:11434/api/generate"
        );
    }

    #[test]
    fn resolve_url_does_not_double_append() {
        assert_eq!(
            resolve_url("http://localhost:11434/api/generate"),
            "http://localhost:11434/api/generate"
        );
        assert_eq!(
            resolve_url("http://localhost:11434/api/generate/"),
            "http://localhost:11434/api/generate"
        );
    }

    #[test]
    fn parse_response_pulls_response_field() {
        let v: serde_json::Value = serde_json::from_str(r#"{"response":"hi"}"#).unwrap();
        assert_eq!(parse_response(&v).unwrap(), "hi");
    }

    #[test]
    fn parse_response_errors_when_missing() {
        let v: serde_json::Value = serde_json::from_str(r#"{"foo":"bar"}"#).unwrap();
        let err = parse_response(&v).unwrap_err();
        assert!(matches!(err, RuntimeError::InvalidArgument { .. }));
        assert!(format!("{err}").contains("response"));
    }
}

