            env.vars.len(),
            env.params.len(),
            env.models.len(),
            env.optim_state.buffers.len()
        )),
        ":describe" => Some(match arg {
            Some(name) => format_describe(env, name),
            None => "usage: :describe <name>".into(),
        }),
        ":help" => arg.and_then(|topic| help_topic(topic, env)),
        _ => None,
    }
