//! HTTP route handlers. Saga 21 step 001.
//!
//! Each handler is a thin axum extractor wrapper
//! around a small piece of business logic in
//! `sessions` or the eval pipeline. Auth is enforced
//! by middleware in `server::build_app`; handlers
//! assume a request that reaches them is already
//! authorized (when auth is required).

use axum::Json;
use axum::extract::{Path, State};
use axum::http::{HeaderMap, StatusCode};
use axum::response::IntoResponse;
use mlpl_eval::{Environment, Value, eval_program_value};
use mlpl_parser::{lex, parse};
use serde::{Deserialize, Serialize};
use uuid::Uuid;

use crate::auth::{AuthMode, check_token, extract_bearer};
use crate::server::AppState;

const VARS_CAP: usize = 200;

#[derive(Serialize)]
pub struct CreateSessionResponse {
    pub session_id: Uuid,
    pub token: String,
}

#[derive(Deserialize)]
pub struct EvalRequest {
    pub program: String,
}

#[derive(Serialize)]
pub struct EvalResponse {
    pub value: String,
    pub kind: &'static str,
}

#[derive(Serialize)]
pub struct ErrorResponse {
    pub error: String,
}

#[derive(Serialize)]
pub struct HealthResponse {
    pub status: &'static str,
    pub version: &'static str,
}

#[derive(Serialize)]
pub struct VarSnapshot {
    pub name: String,
    pub shape: Vec<usize>,
    pub is_param: bool,
}

#[derive(Serialize)]
pub struct InspectResponse {
    pub vars: Vec<VarSnapshot>,
    pub models: Vec<String>,
    pub tokenizers: Vec<String>,
    pub experiments: Vec<String>,
    pub more: usize,
}

/// `POST /v1/sessions` -- no auth. Creates a fresh
/// session and returns its id + bearer token.
pub async fn create_session_handler(State(state): State<AppState>) -> impl IntoResponse {
    let (id, token) = crate::sessions::create_session(&state.sessions).await;
    (
        StatusCode::OK,
        Json(CreateSessionResponse {
            session_id: id,
            token,
        }),
    )
}

/// `POST /v1/sessions/{id}/eval` -- requires bearer
/// when `auth_mode == Required`. Lex + parse + run
/// the program against the session's env, return
/// the stringified value + kind.
pub async fn eval_handler(
    State(state): State<AppState>,
    Path(id): Path<Uuid>,
    headers: HeaderMap,
    Json(body): Json<EvalRequest>,
) -> Result<Json<EvalResponse>, (StatusCode, Json<ErrorResponse>)> {
    let mut sessions = state.sessions.write().await;
    let session = sessions
        .get_mut(&id)
        .ok_or((StatusCode::NOT_FOUND, json_err("unknown session")))?;
    if state.auth_mode == AuthMode::Required {
        let provided = extract_bearer(&headers).ok_or((
            StatusCode::UNAUTHORIZED,
            json_err("missing or invalid authorization"),
        ))?;
        if !check_token(provided, &session.token) {
            return Err((
                StatusCode::UNAUTHORIZED,
                json_err("missing or invalid authorization"),
            ));
        }
    }
    let tokens =
        lex(&body.program).map_err(|e| (StatusCode::BAD_REQUEST, json_err(format!("{e:?}"))))?;
    let stmts =
        parse(&tokens).map_err(|e| (StatusCode::BAD_REQUEST, json_err(format!("{e:?}"))))?;
    let value = eval_program_value(&stmts, &mut session.env)
        .map_err(|e| (StatusCode::BAD_REQUEST, json_err(format!("{e}"))))?;
    let kind = value_kind(&value);
    Ok(Json(EvalResponse {
        value: format!("{value}"),
        kind,
    }))
}

/// `GET /v1/health` -- no auth. Liveness +
/// `CARGO_PKG_VERSION`.
pub async fn health_handler() -> impl IntoResponse {
    Json(HealthResponse {
        status: "ok",
        version: env!("CARGO_PKG_VERSION"),
    })
}

fn json_err(msg: impl Into<String>) -> Json<ErrorResponse> {
    Json(ErrorResponse { error: msg.into() })
}

fn value_kind(value: &Value) -> &'static str {
    match value {
        Value::Array(_) => "array",
        Value::Str(_) => "string",
        Value::Model(_) => "model",
        Value::Tokenizer(_) => "tokenizer",
    }
}

//! Router wiring + server entry. Saga 21 step 001.

use std::net::SocketAddr;

use axum::Router;
use axum::routing::{get, post};

use crate::auth::AuthMode;
use crate::handlers::{create_session_handler, eval_handler, health_handler};
use crate::sessions::{SessionMap, new_map};

/// Errors the server can fail with at startup or
/// while serving. Translated to stderr + non-zero
/// exit by `main`.
#[derive(Debug)]
pub enum ServerError {
    /// `--bind 0.0.0.0` (or any non-loopback) without
    /// `--auth required`.
    InsecureBind { addr: SocketAddr },
    /// Failed to bind the listener socket.
    Bind(std::io::Error),
    /// Axum `serve` returned an error.
    Serve(std::io::Error),
}

impl std::fmt::Display for ServerError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            Self::InsecureBind { addr } => write!(
                f,
                "refusing to bind {addr} with --auth disabled: \
                 non-loopback addresses require --auth required"
            ),
            Self::Bind(e) => write!(f, "bind failed: {e}"),
            Self::Serve(e) => write!(f, "serve failed: {e}"),
        }
    }
}

impl std::error::Error for ServerError {}

/// Shared state on the application: the session map
/// + the configured auth mode.
#[derive(Clone)]
pub struct AppState {
    pub sessions: SessionMap,
    pub auth_mode: AuthMode,
}

/// Build the axum router with the session-map state
/// and auth mode wired in. Used by `run` and by the
/// integration tests (which build their own listener
/// on a random port).
pub fn build_app(auth_mode: AuthMode) -> Router {
    let state = AppState {
        sessions: new_map(),
        auth_mode,
    };
    Router::new()
        .route("/v1/health", get(health_handler))
        .route("/v1/sessions", post(create_session_handler))
        .route("/v1/sessions/:id/eval", post(eval_handler))
        .with_state(state)
}

/// Bind the listener at `addr`, refuse insecure
/// non-loopback binds, then `axum::serve` the
/// router. Used by `main`; tests call `build_app`
/// directly + run on their own listener.
pub async fn run(addr: SocketAddr, auth_mode: AuthMode) -> Result<(), ServerError> {
    if !addr.ip().is_loopback() && auth_mode == AuthMode::Disabled {
        return Err(ServerError::InsecureBind { addr });
    }
    let listener = tokio::net::TcpListener::bind(addr)
        .await
        .map_err(ServerError::Bind)?;
    axum::serve(listener, build_app(auth_mode))
        .await
        .map_err(ServerError::Serve)
}

