//! Saga 21 step 002: `mlpl-repl --connect <url>`
//! delegates every eval to a remote `mlpl-serve`.
//! The local `Environment` is unused; slash commands
//! that read workspace state (`:vars`, `:models`,
//! `:experiments`, `:tokenizers`) call the server's
//! `/inspect` endpoint and render the JSON locally.
//! `:ask` keeps using `mlpl_runtime::call_ollama`
//! directly -- the local `OLLAMA_HOST` /
//! `OLLAMA_MODEL` env vars still override.

use std::io::{self, BufRead, Write};

use serde::Deserialize;

const TIMEOUT_SECS: u64 = 120;

/// Errors returned by the connect-mode HTTP path.
/// Surfaced to stderr; the REPL keeps reading after
/// each one so a transient server error doesn't kill
/// the session.
#[derive(Debug)]
pub enum ClientError {
    Network(String),
    Server { status: u16, message: String },
}

impl std::fmt::Display for ClientError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            Self::Network(m) => write!(f, "network error: {m}"),
            Self::Server { status, message } => write!(f, "server {status}: {message}"),
        }
    }
}

#[derive(Deserialize)]
struct CreateSessionResponse {
    session_id: String,
    token: String,
}

#[derive(Deserialize, Debug)]
pub struct EvalResponse {
    pub value: String,
    pub kind: String,
}

#[derive(Deserialize, Debug)]
pub struct VarSnapshot {
    pub name: String,
    pub shape: Vec<usize>,
    pub is_param: bool,
}

#[derive(Deserialize, Debug)]
pub struct InspectResponse {
    pub vars: Vec<VarSnapshot>,
    pub models: Vec<String>,
    pub tokenizers: Vec<String>,
    pub experiments: Vec<String>,
    pub more: usize,
}

fn build_client() -> reqwest::blocking::Client {
    reqwest::blocking::Client::builder()
        .timeout(std::time::Duration::from_secs(TIMEOUT_SECS))
        .build()
        .expect("blocking reqwest client builds")
}

/// POST `<base>/v1/sessions` with no auth. Returns
/// the (session_id, token) pair to use for every
/// subsequent call.
pub fn create_session(base_url: &str) -> Result<(String, String), ClientError> {
    let client = build_client();
    let resp = client
        .post(format!("{}/v1/sessions", base_url.trim_end_matches('/')))
        .send()
        .map_err(|e| ClientError::Network(e.to_string()))?;
    let status = resp.status().as_u16();
    if !resp.status().is_success() {
        let body = resp.text().unwrap_or_default();
        return Err(ClientError::Server {
            status,
            message: body,
        });
    }
    let body: CreateSessionResponse = resp
        .json()
        .map_err(|e| ClientError::Network(format!("decode: {e}")))?;
    Ok((body.session_id, body.token))
}

/// POST `<base>/v1/sessions/{id}/eval` with the
/// bearer token; returns the server's `{value, kind}`
/// or a `Server` error carrying the 4xx body for
/// surface-level errors (parse, eval, auth).
pub fn eval_remote(
    base_url: &str,
    session_id: &str,
    token: &str,
    program: &str,
) -> Result<EvalResponse, ClientError> {
    let client = build_client();
    let resp = client
        .post(format!(
            "{}/v1/sessions/{session_id}/eval",
            base_url.trim_end_matches('/')
        ))
        .bearer_auth(token)
        .json(&serde_json::json!({"program": program}))
        .send()
        .map_err(|e| ClientError::Network(e.to_string()))?;
    let status = resp.status().as_u16();
    if !resp.status().is_success() {
        let body = resp.text().unwrap_or_default();
        return Err(ClientError::Server {
            status,
            message: extract_error(&body),
        });
    }
    resp.json()
        .map_err(|e| ClientError::Network(format!("decode: {e}")))
}

/// GET `<base>/v1/sessions/{id}/inspect`. Returns
/// the structured workspace snapshot for client-side
/// slash-command rendering.
pub fn inspect_remote(
    base_url: &str,
    session_id: &str,
    token: &str,
) -> Result<InspectResponse, ClientError> {
    let client = build_client();
    let resp = client
        .get(format!(
            "{}/v1/sessions/{session_id}/inspect",
            base_url.trim_end_matches('/')
        ))
        .bearer_auth(token)
        .send()
        .map_err(|e| ClientError::Network(e.to_string()))?;
    let status = resp.status().as_u16();
    if !resp.status().is_success() {
        let body = resp.text().unwrap_or_default();
        return Err(ClientError::Server {
            status,
            message: extract_error(&body),
        });
    }
    resp.json()
        .map_err(|e| ClientError::Network(format!("decode: {e}")))
}

/// Interactive read-eval-print loop in connect
/// mode. Creates a session, then for each line
/// either dispatches a slash command (locally OR
/// against `/inspect`) or POSTs to `/eval`.
pub fn read_loop(base_url: &str) {
    let (session_id, token) = match create_session(base_url) {
        Ok(s) => s,
        Err(e) => {
            eprintln!("error: failed to create session: {e}");
            eprintln!("  is mlpl-serve running at {base_url}?");
            std::process::exit(1);
        }
    };
    println!("Connected to {base_url} (session {session_id})");
    println!("Type :help for commands, exit or Ctrl-D to quit.");
    println!();

    let stdin = io::stdin();
    let mut stdout = io::stdout();
    loop {
        print!("mlpl> ");
        stdout.flush().unwrap();
        let mut line = String::new();
        if stdin.lock().read_line(&mut line).unwrap() == 0 {
            println!();
            break;
        }
        let trimmed = line.trim();
        if trimmed.is_empty() {
            continue;
        }
        if trimmed == "exit" {
            break;
        }
        if let Some(handled) = dispatch_slash(trimmed, base_url, &session_id, &token) {
            if !handled.is_empty() {
                println!("{handled}");
            }
            continue;
        }
        match eval_remote(base_url, &session_id, &token, trimmed) {
            Ok(r) => println!("{}", r.value),
            Err(e) => eprintln!("  {trimmed}\n  error: {e}"),
        }
    }
}

/// Returns `Some(rendered_output)` if the input is a
/// slash command we handle locally; `None` if the
/// caller should fall through to remote eval. Empty
/// string return means "handled, nothing to print"
/// (e.g., `:ask` prints its own output).
fn dispatch_slash(
    input: &str,
    base_url: &str,
    session_id: &str,
    token: &str,
) -> Option<String> {
    if !input.starts_with(':') {
        return None;
    }
    match input {
        ":help" => Some(connect_help_text().into()),
        ":vars" | ":models" | ":experiments" | ":tokenizers" | ":wsid" => {
            match inspect_remote(base_url, session_id, token) {
                Ok(snap) => Some(format_inspect(input, &snap)),
                Err(e) => Some(format!("error: {e}")),
            }
        }
        _ if input == ":ask" || input.starts_with(":ask ") => {
            // Connect-mode `:ask` does NOT use server context;
            // it makes a direct local call to Ollama with no
            // workspace framing (the server-side framing path
            // would need the inspect snapshot threaded into
            // ask.rs, which is a follow-up). The local
            // OLLAMA_HOST / OLLAMA_MODEL env vars still apply.
            let question = input.strip_prefix(":ask").unwrap_or("").trim();
            ask_in_connect_mode(question);
            Some(String::new())
        }
        _ => Some(format!(
            "{input}: not supported in --connect mode (try :vars, :models, :experiments, :tokenizers, :wsid, :ask, :help)"
        )),
    }
}

fn extract_error(body: &str) -> String {
    serde_json::from_str::<serde_json::Value>(body)
        .ok()
        .and_then(|v| v.get("error").and_then(|e| e.as_str()).map(str::to_string))
        .unwrap_or_else(|| body.to_string())
}

fn format_inspect(command: &str, snap: &InspectResponse) -> String {
    let mut out = String::new();
    match command {
        ":vars" => {
            if snap.vars.is_empty() {
                out.push_str("(no variables)");
            } else {
                for v in &snap.vars {
                    let tag = if v.is_param { " [param]" } else { "" };
                    let dims: Vec<String> = v.shape.iter().map(|d| d.to_string()).collect();
                    out.push_str(&format!("  {}: [{}]{tag}\n", v.name, dims.join(", ")));
                }
                if snap.more > 0 {
                    out.push_str(&format!("  ... ({} more)\n", snap.more));
                }
                out.truncate(out.trim_end().len());
            }
        }
        ":models" => {
            if snap.models.is_empty() {
                out.push_str("(no models)");
            } else {
                for m in &snap.models {
                    out.push_str(&format!("  {m}\n"));
                }
                out.truncate(out.trim_end().len());
            }
        }
        ":tokenizers" => {
            if snap.tokenizers.is_empty() {
                out.push_str("(no tokenizers)");
            } else {
                for t in &snap.tokenizers {
                    out.push_str(&format!("  {t}\n"));
                }
                out.truncate(out.trim_end().len());
            }
        }
        ":experiments" => {
            if snap.experiments.is_empty() {
                out.push_str("(no experiments)");
            } else {
                for e in &snap.experiments {
                    out.push_str(&format!("  {e}\n"));
                }
                out.truncate(out.trim_end().len());
            }
        }
        ":wsid" => {
            out.push_str(&format!(
                "workspace (remote):\n  variables: {}\n  models:    {}\n  tokenizers: {}\n  experiments: {}",
                snap.vars.len() + snap.more,
                snap.models.len(),
                snap.tokenizers.len(),
                snap.experiments.len()
            ));
        }
        _ => unreachable!("dispatch_slash filters before format_inspect"),
    }
    out
}

fn ask_in_connect_mode(question: &str) {
    let question = question.trim();
    if question.is_empty() {
        eprintln!("usage: :ask <question>");
        return;
    }
    let host = std::env::var("OLLAMA_HOST")
        .unwrap_or_else(|_| "http://localhost:11434".into());
    let model = std::env::var("OLLAMA_MODEL").unwrap_or_else(|_| "llama3.2".into());
    match mlpl_runtime::call_ollama(&host, question, &model) {
        Ok(answer) => println!("{}", answer.trim_end()),
        Err(e) => eprintln!("error: {e}"),
    }
}

fn connect_help_text() -> &'static str {
    "connect-mode commands:\n  \
     :vars         -- list workspace variables (remote)\n  \
     :models       -- list models (remote)\n  \
     :tokenizers   -- list tokenizers (remote)\n  \
     :experiments  -- list experiment names (remote)\n  \
     :wsid         -- workspace counts (remote)\n  \
     :ask <q>      -- ask local Ollama (no remote workspace framing)\n  \
     :help         -- this message\n  \
     exit, Ctrl-D  -- disconnect"
}

