                }
                out.truncate(out.trim_end().len());
            }
        }
        ":models" => render_name_list(&mut out, "models", &snap.models),
        ":tokenizers" => render_name_list(&mut out, "tokenizers", &snap.tokenizers),
        ":experiments" => render_name_list(&mut out, "experiments", &snap.experiments),
        ":wsid" => {
            out.push_str(&format!(
                "workspace (remote):\n  variables: {}\n  models:    {}\n  tokenizers: {}\n  experiments: {}",
