1	//! Saga 21 step 002: `mlpl-repl --connect <url>`
2	//! delegates every eval to a remote `mlpl-serve`.
3	//! The local `Environment` is unused; slash commands
4	//! that read workspace state (`:vars`, `:models`,
5	//! `:experiments`, `:tokenizers`, `:wsid`) call the
6	//! server's `/inspect` endpoint and render the JSON
7	//! locally. `:ask` keeps using
8	//! `mlpl_runtime::call_ollama` directly -- the local
9	//! `OLLAMA_HOST` / `OLLAMA_MODEL` env vars still
10	//! override.
11	
12	use std::io::{self, BufRead, Write};
13	use std::time::Duration;
14	
15	use serde::Deserialize;
16	
17	const TIMEOUT_SECS: u64 = 120;
18	
19	const CONNECT_HELP: &str = "connect-mode commands:\n  \
20	     :vars         -- list workspace variables (remote)\n  \
21	     :models       -- list models (remote)\n  \
22	     :tokenizers   -- list tokenizers (remote)\n  \
23	     :experiments  -- list experiment names (remote)\n  \
24	     :wsid         -- workspace counts (remote)\n  \
25	     :ask <q>      -- ask local Ollama (no remote workspace framing)\n  \
26	     :help         -- this message\n  \
27	     exit, Ctrl-D  -- disconnect";
28	
29	/// Errors returned by the connect-mode HTTP path.
30	/// Surfaced to stderr; the REPL keeps reading after
31	/// each one so a transient server error doesn't kill
32	/// the session.
33	#[derive(Debug)]
34	pub enum ClientError {
35	    Network(String),
36	    Server { status: u16, message: String },
37	}
38	
39	impl std::fmt::Display for ClientError {
40	    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
41	        match self {
42	            Self::Network(m) => write!(f, "network error: {m}"),
43	            Self::Server { status, message } => write!(f, "server {status}: {message}"),
44	        }
45	    }
46	}
47	
48	#[derive(Deserialize)]
49	struct CreateSessionResponse {
50	    session_id: String,
51	    token: String,
52	}
53	
54	#[derive(Deserialize, Debug)]
55	pub struct EvalResponse {
56	    pub value: String,
57	    /// Tests inspect this; the REPL just prints
58	    /// `value`. A future viz / formatting step may
59	    /// switch on `kind`, so it stays in the
60	    /// deserialized shape.
61	    #[allow(dead_code)]
62	    pub kind: String,
63	}
64	
65	#[derive(Deserialize, Debug)]
66	pub struct VarSnapshot {
67	    pub name: String,
68	    pub shape: Vec<usize>,
69	    pub is_param: bool,
70	}
71	
72	#[derive(Deserialize, Debug)]
73	pub struct InspectResponse {
74	    pub vars: Vec<VarSnapshot>,
75	    pub models: Vec<String>,
76	    pub tokenizers: Vec<String>,
77	    pub experiments: Vec<String>,
78	    pub more: usize,
79	}
80	
81	/// POST `<base>/v1/sessions` with no auth. Returns
82	/// the (session_id, token) pair to use for every
83	/// subsequent call.
84	pub fn create_session(
85	    client: &reqwest::blocking::Client,
86	    base_url: &str,
87	) -> Result<(String, String), ClientError> {
88	    let resp = client
89	        .post(format!("{}/v1/sessions", base_url.trim_end_matches('/')))
90	        .send()
91	        .map_err(|e| ClientError::Network(e.to_string()))?;
92	    let status = resp.status().as_u16();
93	    if !resp.status().is_success() {
94	        let body = resp.text().unwrap_or_default();
95	        return Err(ClientError::Server {
96	            status,
97	            message: body,
98	        });
99	    }
100	    let body: CreateSessionResponse = resp
101	        .json()
102	        .map_err(|e| ClientError::Network(format!("decode: {e}")))?;
103	    Ok((body.session_id, body.token))
104	}
105	
106	/// POST `<base>/v1/sessions/{id}/eval` with the
107	/// bearer token; returns the server's `{value, kind}`
108	/// or a `Server` error carrying the unwrapped
109	/// `error` string for surface-level errors (parse,
110	/// eval, auth).
111	pub fn eval_remote(
112	    client: &reqwest::blocking::Client,
113	    base_url: &str,
114	    session_id: &str,
115	    token: &str,
116	    program: &str,
117	) -> Result<EvalResponse, ClientError> {
118	    let resp = client
119	        .post(format!(
120	            "{}/v1/sessions/{session_id}/eval",
121	            base_url.trim_end_matches('/')
122	        ))
123	        .bearer_auth(token)
124	        .json(&serde_json::json!({"program": program}))
125	        .send()
126	        .map_err(|e| ClientError::Network(e.to_string()))?;
127	    let status = resp.status().as_u16();
128	    if !resp.status().is_success() {
129	        let body = resp.text().unwrap_or_default();
130	        let message = serde_json::from_str::<serde_json::Value>(&body)
131	            .ok()
132	            .and_then(|v| v.get("error").and_then(|e| e.as_str()).map(str::to_string))
133	            .unwrap_or(body);
134	        return Err(ClientError::Server { status, message });
135	    }
136	    resp.json()
137	        .map_err(|e| ClientError::Network(format!("decode: {e}")))
138	}
139	
140	/// GET `<base>/v1/sessions/{id}/inspect`. Returns
141	/// the structured workspace snapshot for client-side
142	/// slash-command rendering.
143	pub fn inspect_remote(
144	    client: &reqwest::blocking::Client,
145	    base_url: &str,
146	    session_id: &str,
147	    token: &str,
148	) -> Result<InspectResponse, ClientError> {
149	    let resp = client
150	        .get(format!(
151	            "{}/v1/sessions/{session_id}/inspect",
152	            base_url.trim_end_matches('/')
153	        ))
154	        .bearer_auth(token)
155	        .send()
156	        .map_err(|e| ClientError::Network(e.to_string()))?;
157	    let status = resp.status().as_u16();
158	    if !resp.status().is_success() {
159	        let body = resp.text().unwrap_or_default();
160	        let message = serde_json::from_str::<serde_json::Value>(&body)
161	            .ok()
162	            .and_then(|v| v.get("error").and_then(|e| e.as_str()).map(str::to_string))
163	            .unwrap_or(body);
164	        return Err(ClientError::Server { status, message });
165	    }
166	    resp.json()
167	        .map_err(|e| ClientError::Network(format!("decode: {e}")))
168	}
169	
170	/// Interactive read-eval-print loop in connect
171	/// mode. Creates a session, then for each line
172	/// either dispatches a slash command (locally OR
173	/// against `/inspect`) or POSTs to `/eval`.
174	pub fn read_loop(base_url: &str) {
175	    let client = reqwest::blocking::Client::builder()
176	        .timeout(Duration::from_secs(TIMEOUT_SECS))
177	        .build()
178	        .expect("blocking reqwest client builds");
179	    let (session_id, token) = match create_session(&client, base_url) {
180	        Ok(s) => s,
181	        Err(e) => {
182	            eprintln!("error: failed to create session: {e}");
183	            eprintln!("  is mlpl-serve running at {base_url}?");
184	            std::process::exit(1);
185	        }
186	    };
187	    println!("Connected to {base_url} (session {session_id})");
188	    println!("Type :help for commands, exit or Ctrl-D to quit.");
189	    println!();
190	
191	    let stdin = io::stdin();
192	    let mut stdout = io::stdout();
193	    loop {
194	        print!("mlpl> ");
195	        stdout.flush().unwrap();
196	        let mut line = String::new();
197	        if stdin.lock().read_line(&mut line).unwrap() == 0 {
198	            println!();
199	            break;
200	        }
201	        let trimmed = line.trim();
202	        if trimmed.is_empty() {
203	            continue;
204	        }
205	        if trimmed == "exit" {
206	            break;
207	        }
