10	use axum::Json;
11	use axum::extract::{Path, State};
12	use axum::http::{HeaderMap, StatusCode};
13	use axum::response::IntoResponse;
14	use mlpl_eval::{Environment, Value, eval_program_value};
15	use mlpl_parser::{lex, parse};
16	use serde::{Deserialize, Serialize};
17	use uuid::Uuid;
18	
19	use crate::auth::{AuthMode, check_token, extract_bearer};
20	use crate::server::AppState;
21	
22	const VARS_CAP: usize = 200;
23	
24	#[derive(Serialize)]
25	pub struct CreateSessionResponse {
26	    pub session_id: Uuid,
27	    pub token: String,
28	}
