68	/// `POST /v1/sessions` -- no auth. Creates a fresh
69	/// session and returns its id + bearer token.
70	pub async fn create_session_handler(State(state): State<AppState>) -> impl IntoResponse {
71	    let (id, token) = crate::sessions::create_session(&state.sessions).await;
72	    (
73	        StatusCode::OK,
74	        Json(CreateSessionResponse {
75	            session_id: id,
76	            token,
77	        }),
78	    )
79	}
