81	/// `POST /v1/sessions/{id}/eval` -- requires bearer
82	/// when `auth_mode == Required`. Lex + parse + run
83	/// the program against the session's env, return
84	/// the stringified value + kind.
85	pub async fn eval_handler(
86	    State(state): State<AppState>,
87	    Path(id): Path<Uuid>,
88	    headers: HeaderMap,
89	    Json(body): Json<EvalRequest>,
90	) -> Result<Json<EvalResponse>, (StatusCode, Json<ErrorResponse>)> {
91	    let mut sessions = state.sessions.write().await;
92	    let session = sessions
93	        .get_mut(&id)
94	        .ok_or((StatusCode::NOT_FOUND, json_err("unknown session")))?;
95	    if state.auth_mode == AuthMode::Required {
96	        let provided = extract_bearer(&headers).ok_or((
97	            StatusCode::UNAUTHORIZED,
98	            json_err("missing or invalid authorization"),
99	        ))?;
100	        if !check_token(provided, &session.token) {
101	            return Err((
102	                StatusCode::UNAUTHORIZED,
103	                json_err("missing or invalid authorization"),
104	            ));
105	        }
106	    }
107	    let tokens =
108	        lex(&body.program).map_err(|e| (StatusCode::BAD_REQUEST, json_err(format!("{e:?}"))))?;
109	    let stmts =
110	        parse(&tokens).map_err(|e| (StatusCode::BAD_REQUEST, json_err(format!("{e:?}"))))?;
111	    let value = eval_program_value(&stmts, &mut session.env)
112	        .map_err(|e| (StatusCode::BAD_REQUEST, json_err(format!("{e}"))))?;
113	    let kind = value_kind(&value);
114	    Ok(Json(EvalResponse {
115	        value: format!("{value}"),
116	        kind,
117	    }))
118	}
