121	/// `CARGO_PKG_VERSION`.
122	pub async fn health_handler() -> impl IntoResponse {
123	    Json(HealthResponse {
124	        status: "ok",
125	        version: env!("CARGO_PKG_VERSION"),
126	    })
127	}
