129	/// `GET /v1/sessions/{id}/inspect` -- requires
130	/// bearer when `auth_mode == Required`. Returns a
131	/// JSON snapshot of the session's workspace
132	/// (variable names + shapes + `[param]` tags, model
133	/// names, tokenizer names, experiment names). Vars
134	/// capped at 200 entries; the `more` field reports
135	/// how many were truncated.
136	pub async fn inspect_handler(
137	    State(state): State<AppState>,
138	    Path(id): Path<Uuid>,
139	    headers: HeaderMap,
140	) -> Result<Json<InspectResponse>, (StatusCode, Json<ErrorResponse>)> {
141	    let sessions = state.sessions.read().await;
142	    let session = sessions
143	        .get(&id)
144	        .ok_or((StatusCode::NOT_FOUND, json_err("unknown session")))?;
145	    if state.auth_mode == AuthMode::Required {
146	        let provided = extract_bearer(&headers).ok_or((
147	            StatusCode::UNAUTHORIZED,
148	            json_err("missing or invalid authorization"),
149	        ))?;
150	        if !check_token(provided, &session.token) {
151	            return Err((
152	                StatusCode::UNAUTHORIZED,
153	                json_err("missing or invalid authorization"),
154	            ));
155	        }
156	    }
157	    Ok(Json(snapshot_env(&session.env)))
158	}
159	
160	fn snapshot_env(env: &Environment) -> InspectResponse {
161	    let mut vars: Vec<VarSnapshot> = env
162	        .vars_iter()
163	        .map(|(name, arr)| VarSnapshot {
164	            name: name.clone(),
165	            shape: arr.shape().dims().to_vec(),
166	            is_param: env.is_param(name),
167	        })
168	        .collect();
169	    vars.sort_by(|a, b| a.name.cmp(&b.name));
170	    let total = vars.len();
171	    let more = total.saturating_sub(VARS_CAP);
172	    vars.truncate(VARS_CAP);
173	    let mut models: Vec<String> = env.models_iter().map(|(n, _)| n.clone()).collect();
174	    models.sort();
175	    let mut tokenizers: Vec<String> = env.tokenizers_iter().map(|(n, _)| n.clone()).collect();
176	    tokenizers.sort();
177	    let mut experiments: Vec<String> = env
178	        .experiment_log()
179	        .iter()
180	        .map(|r| r.name.clone())
181	        .collect();
182	    experiments.sort();
183	    experiments.dedup();
184	    InspectResponse {
185	        vars,
186	        models,
187	        tokenizers,
188	        experiments,
189	        more,
190	    }
191	}
192	
193	fn json_err(msg: impl Into<String>) -> Json<ErrorResponse> {
194	    Json(ErrorResponse { error: msg.into() })
195	}
196	
197	fn value_kind(value: &Value) -> &'static str {
198	    match value {
199	        Value::Array(_) => "array",
200	        Value::Str(_) => "string",
201	        Value::Model(_) => "model",
202	        Value::Tokenizer(_) => "tokenizer",
203	    }
204	}

