fn main() {
    let args: Vec<String> = std::env::args().collect();
    if args.iter().any(|a| a == "-V" || a == "--version") {
        version::print();
        return;
    }

    // Saga 21 step 002: --connect <url> delegates eval
    // to a remote mlpl-serve. Cannot combine with -f
    // or --data-dir / --exp-dir (those are local-mode
    // only).
    let connect_url = args
        .iter()
        .position(|a| a == "--connect")
        .and_then(|p| args.get(p + 1))
        .cloned();
    if let Some(url) = connect_url {
        let conflicts = ["-f", "--file", "--data-dir", "--exp-dir"];
        if let Some(bad) = args.iter().find(|a| conflicts.contains(&a.as_str())) {
            eprintln!(
                "error: --connect cannot be combined with {bad}\n  \
                 --connect delegates evaluation to a remote server; \
                 -f, --data-dir, and --exp-dir are local-mode only."
            );
            std::process::exit(2);
        }
        connect::read_loop(&url);
        return;
    }

    let mut env = Environment::new();
    let trace_flag = args.iter().any(|a| a == "--trace");
    let svg_dir = args
        .iter()
        .position(|a| a == "--svg-out")
        .and_then(|p| args.get(p + 1))
        .map(PathBuf::from);
    let mut svg_out = SvgOut::new(svg_dir);

    // Sandbox root for `load("relative.csv")` etc. Saga 12 step 001.
    // Unset by default -- `load` without a sandbox errors cleanly.
    if let Some(dir) = args
        .iter()
        .position(|a| a == "--data-dir")
        .and_then(|p| args.get(p + 1))
    {
        env.set_data_dir(PathBuf::from(dir));
    }
