1	//! Saga 21 step 002: connect-mode REPL loop +
2	//! slash-command dispatch + `--connect` argv parser.
3	//! Pure HTTP transport lives in `connect.rs`.
4	
5	use std::io::{self, BufRead, Write};
6	
7	use crate::connect::{InspectResponse, build_client, create_session, eval_remote, inspect_remote};
8	
9	const CONNECT_HELP: &str = "connect-mode commands:\n  \
10	     :vars         -- list workspace variables (remote)\n  \
11	     :models       -- list models (remote)\n  \
12	     :tokenizers   -- list tokenizers (remote)\n  \
13	     :experiments  -- list experiment names (remote)\n  \
14	     :wsid         -- workspace counts (remote)\n  \
15	     :ask <q>      -- ask local Ollama (no remote workspace framing)\n  \
16	     :help         -- this message\n  \
17	     exit, Ctrl-D  -- disconnect";
18	
19	/// Inspect argv for `--connect <url>`. If present,
20	/// validate that no local-mode-only flags are also
21	/// set (`-f`, `--file`, `--data-dir`, `--exp-dir`),
22	/// run the connect-mode loop, and return `true` to
23	/// signal the caller (`main`) to exit. Returns
24	/// `false` if `--connect` was not present so the
25	/// caller continues into local mode.
26	pub fn try_dispatch_args(args: &[String]) -> bool {
27	    let url = match args
28	        .iter()
29	        .position(|a| a == "--connect")
30	        .and_then(|p| args.get(p + 1))
31	    {
32	        Some(u) => u.clone(),
33	        None => return false,
34	    };
35	    let conflicts = ["-f", "--file", "--data-dir", "--exp-dir"];
36	    if let Some(bad) = args.iter().find(|a| conflicts.contains(&a.as_str())) {
37	        eprintln!(
38	            "error: --connect cannot be combined with {bad}\n  \
39	             --connect delegates evaluation to a remote server; \
40	             -f, --data-dir, and --exp-dir are local-mode only."
41	        );
42	        std::process::exit(2);
43	    }
44	    read_loop(&url);
45	    true
46	}
47	
48	/// Interactive read-eval-print loop in connect
49	/// mode. Creates a session, then for each line
50	/// either dispatches a slash command (locally OR
51	/// against `/inspect`) or POSTs to `/eval`.
52	pub fn read_loop(base_url: &str) {
53	    let client = build_client();
54	    let (session_id, token) = match create_session(&client, base_url) {
55	        Ok(s) => s,
56	        Err(e) => {
57	            eprintln!("error: failed to create session: {e}");
58	            eprintln!("  is mlpl-serve running at {base_url}?");
59	            std::process::exit(1);
60	        }
61	    };
62	    println!("Connected to {base_url} (session {session_id})");
63	    println!("Type :help for commands, exit or Ctrl-D to quit.");
64	    println!();
65	
66	    let stdin = io::stdin();
67	    let mut stdout = io::stdout();
68	    loop {
69	        print!("mlpl> ");
70	        stdout.flush().unwrap();
71	        let mut line = String::new();
72	        if stdin.lock().read_line(&mut line).unwrap() == 0 {
73	            println!();
74	            break;
75	        }
76	        let trimmed = line.trim();
77	        if trimmed.is_empty() {
78	            continue;
79	        }
80	        if trimmed == "exit" {
81	            break;
82	        }
83	        if let Some(out) = dispatch_slash(&client, trimmed, base_url, &session_id, &token) {
84	            if !out.is_empty() {
85	                println!("{out}");
86	            }
87	            continue;
88	        }
89	        match eval_remote(&client, base_url, &session_id, &token, trimmed) {
90	            Ok(r) => println!("{}", r.value),
91	            Err(e) => eprintln!("  {trimmed}\n  error: {e}"),
92	        }
93	    }
94	}
95	
96	/// Returns `Some(rendered_output)` if the input is a
97	/// slash command we handle in connect mode. Empty
98	/// string means "handled, nothing to print" (e.g.,
99	/// `:ask` prints its own output). `None` means the
100	/// caller should fall through to remote eval -- but
101	/// in connect mode all `:`-prefixed lines are
102	/// considered slash commands; non-supported ones
103	/// return a "(not supported)" message rather than
104	/// being POSTed as MLPL source.
105	fn dispatch_slash(
106	    client: &reqwest::blocking::Client,
107	    input: &str,
108	    base_url: &str,
109	    session_id: &str,
110	    token: &str,
111	) -> Option<String> {
112	    if !input.starts_with(':') {
113	        return None;
114	    }
115	    match input {
116	        ":help" => Some(CONNECT_HELP.into()),
117	        ":vars" | ":models" | ":experiments" | ":tokenizers" | ":wsid" => {
118	            match inspect_remote(client, base_url, session_id, token) {
119	                Ok(snap) => Some(format_inspect(input, &snap)),
120	                Err(e) => Some(format!("error: {e}")),
121	            }
122	        }
123	        _ if input == ":ask" || input.starts_with(":ask ") => {
124	            // Connect-mode `:ask` does NOT thread server
125	            // workspace context into the prompt -- the
126	            // server-side framing path would need the inspect
127	            // snapshot composed into ask.rs's helpers, which
128	            // is a follow-up. The local OLLAMA_HOST /
129	            // OLLAMA_MODEL env vars still apply.
130	            let question = input.strip_prefix(":ask").unwrap_or("").trim();
131	            if question.is_empty() {
132	                eprintln!("usage: :ask <question>");
133	            } else {
134	                let host = std::env::var("OLLAMA_HOST")
135	                    .unwrap_or_else(|_| "http://localhost:11434".into());
136	                let model = std::env::var("OLLAMA_MODEL").unwrap_or_else(|_| "llama3.2".into());
137	                match mlpl_runtime::call_ollama(&host, question, &model) {
138	                    Ok(answer) => println!("{}", answer.trim_end()),
139	                    Err(e) => eprintln!("error: {e}"),
140	                }
141	            }
142	            Some(String::new())
143	        }
144	        _ => Some(format!(
145	            "{input}: not supported in --connect mode (try :vars, :models, :experiments, :tokenizers, :wsid, :ask, :help)"
146	        )),
147	    }
148	}
149	
150	fn format_inspect(command: &str, snap: &InspectResponse) -> String {
151	    let mut out = String::new();
152	    let render_names = |out: &mut String, label: &str, names: &[String]| {
153	        if names.is_empty() {
154	            out.push_str(&format!("(no {label})"));
155	        } else {
156	            for n in names {
157	                out.push_str(&format!("  {n}\n"));
158	            }
159	            out.truncate(out.trim_end().len());
160	        }
161	    };
162	    match command {
163	        ":vars" => {
164	            if snap.vars.is_empty() {
165	                out.push_str("(no variables)");
166	            } else {
167	                for v in &snap.vars {
168	                    let tag = if v.is_param { " [param]" } else { "" };
169	                    let dims: Vec<String> = v.shape.iter().map(|d| d.to_string()).collect();
170	                    out.push_str(&format!("  {}: [{}]{tag}\n", v.name, dims.join(", ")));
171	                }
172	                if snap.more > 0 {
173	                    out.push_str(&format!("  ... ({} more)\n", snap.more));
174	                }
175	                out.truncate(out.trim_end().len());
176	            }
177	        }
178	        ":models" => render_names(&mut out, "models", &snap.models),
179	        ":tokenizers" => render_names(&mut out, "tokenizers", &snap.tokenizers),
180	        ":experiments" => render_names(&mut out, "experiments", &snap.experiments),
181	        ":wsid" => {
182	            out.push_str(&format!(
183	                "workspace (remote):\n  variables: {}\n  models:    {}\n  tokenizers: {}\n  experiments: {}",
184	                snap.vars.len() + snap.more,
185	                snap.models.len(),
186	                snap.tokenizers.len(),
187	                snap.experiments.len()
188	            ));
189	        }
190	        _ => unreachable!("dispatch_slash filters before format_inspect"),
191	    }
192	    out
193	}

