18	        if let Some(dir) = &self.dir {
19	            self.counter += 1;
20	            let path = dir.join(format!("svg-{:03}.svg", self.counter));
21	            match std::fs::write(&path, svg) {
22	                Ok(()) => println!("[svg: {} bytes -> {}]", svg.len(), path.display()),
23	                Err(e) => eprintln!("[svg: error writing {}: {e}]", path.display()),
24	            }
25	        } else {
26	            println!("[svg: {} bytes -- pass --svg-out <dir> to save]", svg.len());
27	        }
28	    }
29	}
