20	    if connect_repl::try_dispatch_args(&args) {
21	        return;
22	    }
23	    let flag = |name: &str| -> Option<String> {
24	        args.iter()
25	            .position(|a| a == name)
26	            .and_then(|p| args.get(p + 1))
27	            .cloned()
28	    };
29	    let mut env = Environment::new();
30	    let trace_flag = args.iter().any(|a| a == "--trace");
31	    let mut svg_out = SvgOut::new(flag("--svg-out").map(PathBuf::from));
32	    if let Some(dir) = flag("--data-dir") {
33	        env.set_data_dir(PathBuf::from(dir));
34	    }
35	    if let Some(dir) = flag("--exp-dir") {
36	        env.set_exp_dir(PathBuf::from(dir));
37	    }
38	    if let Some(path) = flag("-f").or_else(|| flag("--file")) {
39	        let content = std::fs::read_to_string(&path).unwrap_or_else(|e| {
40	            eprintln!("error reading {path}: {e}");
41	            std::process::exit(1);
42	        });
43	        run_script(&content, &mut env, trace_flag, &mut svg_out);
44	    } else {
