49	fn run_interactive(env: &mut Environment, svg_out: &mut SvgOut) {
50	    println!("{}", version::banner());
51	    println!("Type :help for commands, exit or Ctrl-D to quit.");
52	    println!();
53	
54	    let stdin = io::stdin();
55	    let mut stdout = io::stdout();
56	    let mut tracing = false;
57	    let mut last_trace: Option<Trace> = None;
58	
59	    loop {
60	        print!("mlpl> ");
61	        stdout.flush().unwrap();
62	
63	        let mut line = String::new();
64	        if stdin.lock().read_line(&mut line).unwrap() == 0 {
65	            println!();
66	            break;
67	        }
68	
69	        let trimmed = line.trim();
70	        if trimmed.is_empty() {
71	            continue;
72	        }
73	        if trimmed == "exit" {
74	            break;
75	        }
76	
77	        if handle_command(trimmed, &mut tracing, &last_trace, env) {
78	            continue;
79	        }
80	
81	        eval_line(trimmed, env, tracing, &mut last_trace, svg_out);
82	    }
83	}
