85	fn run_script(content: &str, env: &mut Environment, tracing: bool, svg_out: &mut SvgOut) {
86	    // Strip comment-only lines but preserve structure for multi-line constructs
87	    let cleaned: Vec<&str> = content
88	        .lines()
89	        .map(|line| {
90	            let trimmed = line.trim();
91	            if trimmed.starts_with('#') { "" } else { line }
92	        })
93	        .collect();
94	    let source = cleaned.join("\n");
95	    let trimmed = source.trim();
96	    if trimmed.is_empty() {
97	        return;
98	    }
99	    for line in content.lines() {
100	        let t = line.trim();
101	        if !t.is_empty() && !t.starts_with('#') {
102	            println!("> {t}");
103	        }
104	    }
105	    let mut last_trace: Option<Trace> = None;
106	    eval_line(trimmed, env, tracing, &mut last_trace, svg_out);
107	    if let Some(trace) = &last_trace {
108	        println!();
109	        print_trace_summary(trace);
110	    }
111	}
