113	fn handle_command(
114	    input: &str,
115	    tracing: &mut bool,
116	    last_trace: &Option<Trace>,
117	    env: &mut Environment,
118	) -> bool {
119	    if !input.starts_with(':') {
120	        return false;
121	    }
122	    match input {
123	        ":help" => print_help(),
124	        ":version" => println!("{}", version::banner()),
125	        ":clear" => {
126	            *env = Environment::new();
127	            println!("Environment cleared.");
128	        }
129	        ":trace on" => {
130	            *tracing = true;
131	            println!("Tracing enabled.");
132	        }
133	        ":trace off" => {
134	            *tracing = false;
135	            println!("Tracing disabled.");
136	        }
137	        ":trace json" => match last_trace {
138	            Some(t) => println!("{}", t.to_json()),
139	            None => eprintln!("No trace available. Use :trace on first."),
140	        },
141	        ":trace" => match last_trace {
142	            Some(t) => print_trace_summary(t),
143	            None => eprintln!("No trace available. Use :trace on first."),
144	        },
145	        _ if input.starts_with(":trace json ") => {
146	            let path = input.strip_prefix(":trace json ").unwrap().trim();
147	            match last_trace {
148	                Some(t) => match std::fs::write(path, t.to_json()) {
149	                    Ok(()) => println!("Trace written to {path}"),
150	                    Err(e) => eprintln!("error writing file: {e}"),
151	                },
152	                None => eprintln!("No trace available. Use :trace on first."),
153	            }
154	        }
155	        _ if input == ":ask" || input.starts_with(":ask ") => {
156	            ask::dispatch(input.strip_prefix(":ask").unwrap_or("").trim(), env);
157	        }
158	        _ => match mlpl_eval::inspect(env, input) {
159	            Some(out) => println!("{out}"),
160	            None => eprintln!("Unknown command: {input}. Type :help for available commands."),
161	        },
162	    }
163	    true
164	}
