166	fn eval_line(
167	    input: &str,
168	    env: &mut Environment,
169	    tracing: bool,
170	    last_trace: &mut Option<Trace>,
171	    svg_out: &mut SvgOut,
172	) {
173	    let report_err = |e: &dyn std::fmt::Display| {
174	        eprintln!("  {input}");
175	        eprintln!("  error: {e}");
176	    };
177	    let tokens = match mlpl_parser::lex(input) {
178	        Ok(t) => t,
179	        Err(e) => return report_err(&e),
180	    };
181	    let stmts = match mlpl_parser::parse(&tokens) {
182	        Ok(s) if s.is_empty() => return,
183	        Ok(s) => s,
184	        Err(e) => return report_err(&e),
185	    };
186	    if tracing {
187	        let mut trace = Trace::new(input.into());
188	        match mlpl_eval::eval_program_traced(&stmts, env, &mut trace) {
189	            Ok(arr) => {
190	                println!("{arr}");
191	                *last_trace = Some(trace);
192	            }
193	            Err(e) => report_err(&e),
194	        }
195	    } else {
196	        match mlpl_eval::eval_program_value(&stmts, env) {
197	            Ok(value) => {
198	                let formatted = format!("{value}");
199	                let display =
200	                    mlpl_cli::viz_cache::transform_value(&formatted, svg_out.dir.as_deref());
201	                println!("{display}");
202	            }
203	            Err(e) => report_err(&e),
204	        }
205	    }
206	}
